import api from "./axios";

export const updateVehicle = (id, formData) => api.put(`/vehicles/${id}`, formData);
export const addVehicle = (formData) => api.post("/vehicles", formData);

export const deleteVehicleImage = (vehicleId, filename) =>
  api.delete(`/vehicles/${vehicleId}/images/${encodeURIComponent(filename)}`);

export const getVehicles = () => api.get("/vehicles");
export const getVehicleById = (id) => api.get(`/vehicles/${id}`);
export const deleteVehicle = (id) => api.delete(`/vehicles/${id}`);
